import pika
import json
import time
import sys
import uuid
from datetime import datetime
from typing import Callable, Optional


class RabbitMQConnection:
    """Base class for RabbitMQ connections with common configuration."""

    def __init__(
        self,
        host: str = "localhost",
        port: int = 5672,
        username: str = "guest",
        password: str = "guest",
        virtual_host: str = "/",
        queue_name: str = "task_queue",
        exchange_name: str = "task_exchange",
        routing_key: str = "task_routing_key",
    ):
        self.host = host
        self.port = port
        self.username = username
        self.password = password
        self.virtual_host = virtual_host
        self.queue_name = queue_name
        self.exchange_name = exchange_name
        self.routing_key = routing_key
        self.connection = None
        self.channel = None

    def connect(self):
        """Establish connection to RabbitMQ server."""
        credentials = pika.PlainCredentials(self.username, self.password)
        parameters = pika.ConnectionParameters(
            host=self.host,
            port=self.port,
            virtual_host=self.virtual_host,
            credentials=credentials,
            heartbeat=600,
            blocked_connection_timeout=300,
        )

        self.connection = pika.BlockingConnection(parameters)
        self.channel = self.connection.channel()

        # Declare a durable exchange
        self.channel.exchange_declare(
            exchange=self.exchange_name,
            exchange_type="direct",
            durable=True,
        )

        # Declare a durable queue
        self.channel.queue_declare(
            queue=self.queue_name,
            durable=True,
            arguments={
                "x-message-ttl": 86400000,  # 24 hours TTL
                "x-max-length": 100000,  # Max 100k messages
                "x-dead-letter-exchange": f"{self.exchange_name}.dlx",
                "x-dead-letter-routing-key": f"{self.routing_key}.dlx",
            },
        )

        # Bind queue to exchange
        self.channel.queue_bind(
            exchange=self.exchange_name,
            queue=self.queue_name,
            routing_key=self.routing_key,
        )

        # Set up dead letter exchange and queue
        self._setup_dead_letter_queue()

        print(f"[*] Connected to RabbitMQ at {self.host}:{self.port}")

    def _setup_dead_letter_queue(self):
        """Set up dead letter exchange and queue for failed messages."""
        dlx_exchange = f"{self.exchange_name}.dlx"
        dlx_queue = f"{self.queue_name}.dlx"
        dlx_routing_key = f"{self.routing_key}.dlx"

        self.channel.exchange_declare(
            exchange=dlx_exchange,
            exchange_type="direct",
            durable=True,
        )

        self.channel.queue_declare(
            queue=dlx_queue,
            durable=True,
        )

        self.channel.queue_bind(
            exchange=dlx_exchange,
            queue=dlx_queue,
            routing_key=dlx_routing_key,
        )

    def close(self):
        """Close the connection."""
        if self.connection and not self.connection.is_closed:
            self.connection.close()
            print("[*] Connection closed")


class TaskPublisher(RabbitMQConnection):
    """Publisher that sends task messages to RabbitMQ."""

    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        self._delivery_confirmations = True

    def connect(self):
        """Connect and enable delivery confirmations."""
        super().connect()
        if self._delivery_confirmations:
            self.channel.confirm_delivery()
            print("[*] Delivery confirmations enabled")

    def publish_task(
        self,
        task_type: str,
        payload: dict,
        priority: int = 0,
        correlation_id: Optional[str] = None,
    ) -> str:
        """
        Publish a task message to the queue.

        Args:
            task_type: Type of task to execute
            payload: Task data/parameters
            priority: Message priority (0-9)
            correlation_id: Optional correlation ID for tracking

        Returns:
            The message ID of the published task
        """
        message_id = str(uuid.uuid4())
        if correlation_id is None:
            correlation_id = message_id

        message = {
            "message_id": message_id,
            "correlation_id": correlation_id,
            "task_type": task_type,
            "payload": payload,
            "priority": priority,
            "timestamp": datetime.utcnow().isoformat(),
            "retry_count": 0,
            "max_retries": 3,
        }

        properties = pika.BasicProperties(
            delivery_mode=2,  # Persistent message
            content_type="application/json",
            message_id=message_id,
            correlation_id=correlation_id,
            priority=priority,
            timestamp=int(time.time()),
            headers={
                "task_type": task_type,
                "version": "1.0",
            },
        )

        try:
            self.channel.basic_publish(
                exchange=self.exchange_name,
                routing_key=self.routing_key,
                body=json.dumps(message),
                properties=properties,
                mandatory=True,
            )
            print(f"[x] Published task: {task_type} (ID: {message_id})")
            return message_id

        except pika.exceptions.UnroutableError:
            print(f"[!] Message was returned (unroutable): {message_id}")
            raise
        except pika.exceptions.NackError:
            print(f"[!] Message was NACKed by broker: {message_id}")
            raise

    def publish_batch(self, tasks: list) -> list:
        """
        Publish multiple tasks in batch.

        Args:
            tasks: List of dicts with 'task_type' and 'payload' keys

        Returns:
            List of message IDs
        """
        message_ids = []
        for task in tasks:
            msg_id = self.publish_task(
                task_type=task["task_type"],
                payload=task.get("payload", {}),
                priority=task.get("priority", 0),
            )
            message_ids.append(msg_id)

        print(f"[x] Published batch of {len(message_ids)} tasks")
        return message_ids


class TaskConsumer(RabbitMQConnection):
    """Consumer that processes task messages from RabbitMQ."""

    def __init__(self, prefetch_count: int = 1, **kwargs):
        super().__init__(**kwargs)
        self.prefetch_count = prefetch_count
        self._task_handlers: dict[str, Callable] = {}
        self._default_handler: Optional[Callable] = None

    def connect(self):
        """Connect and set QoS prefetch."""
        super().connect()
        self.channel.basic_qos(prefetch_count=self.prefetch_count)
        print(f"[*] Prefetch count set to {self.prefetch_count}")

    def register_handler(self, task_type: str, handler: Callable):
        """
        Register a handler function for a specific task type.

        Args:
            task_type: The task type string to handle
            handler: Callable that takes (task_type, payload) and returns a result
        """
        self._task_handlers[task_type] = handler
        print(f"[*] Registered handler for task type: {task_type}")

    def set_default_handler(self, handler: Callable):
        """Set a default handler for unregistered task types."""
        self._default_handler = handler
        print("[*] Default handler set")

    def _on_message(self, channel, method, properties, body):
        """
        Callback for processing received messages.

        Handles deserialization, routing to appropriate handler,
        acknowledgment, and error handling with retry logic.
        """
        message_id = properties.message_id or "unknown"
        print(f"\n[>] Received message (ID: {message_id})")

        try:
            message = json.loads(body)
        except json.JSONDecodeError as e:
            print(f"[!] Failed to decode message: {e}")
            # Reject without requeue for malformed messages
            channel.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
            return

        task_type = message.get("task_type", "unknown")
        payload = message.get("payload", {})
        retry_count = message.get("retry_count", 0)
        max_retries = message.get("max_retries", 3)

        print(f"[>] Task type: {task_type}")
        print(f"[>] Payload: {json.dumps(payload, indent=2)}")
        print(f"[>] Retry count: {retry_count}/{max_retries}")

        handler = self._task_handlers.get(task_type, self._default_handler)

        if handler is None:
            print(f"[!] No handler registered for task type: {task_type}")
            channel.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
            return

        try:
            start_time = time.time()
            result = handler(task_type, payload)
            elapsed = time.time() - start_time

            print(f"[✓] Task completed in {elapsed:.3f}s")
            if result is not None:
                print(f"[✓] Result: {result}")

            # Acknowledge successful processing
            channel.basic_ack(delivery_tag=method.delivery_tag)

        except Exception as e:
            print(f"[!] Task processing failed: {e}")

            if retry_count < max_retries:
                # Retry: republish with incremented retry count
                print(f"[!] Retrying ({retry_count + 1}/{max_retries})...")
                message["retry_count"] = retry_count + 1

                retry_properties = pika.BasicProperties(
                    delivery_mode=2,
                    content_type="application/json",
                    message_id=str(uuid.uuid4()),
                    correlation_id=properties.correlation_id,
                    headers={
                        "task_type": task_type,
                        "version": "1.0",
                        "retry_count": retry_count + 1,
                        "original_message_id": message_id,
                    },
                )

                channel.basic_publish(
                    exchange=self.exchange_name,
                    routing_key=self.routing_key,
                    body=json.dumps(message),
                    properties=retry_properties,
                )

                # Ack the original message since we've republished
                channel.basic_ack(delivery_tag=method.delivery_tag)
            else:
                print(f"[!] Max retries exceeded. Sending to dead letter queue.")
                # Reject without requeue - goes to DLX
                channel.basic_nack(delivery_tag=method.delivery_tag, requeue=False)

    def start_consuming(self):
        """Start consuming messages from the queue."""
        self.channel.basic_consume(
            queue=self.queue_name,
            on_message_callback=self._on_message,
            auto_ack=False,
        )

        print(f"[*] Waiting for tasks on queue: {self.queue_name}")
        print("[*] Press CTRL+C to stop")

        try:
            self.channel.start_consuming()
        except KeyboardInterrupt:
            print("\n[*] Stopping consumer...")
            self.channel.stop_consuming()
        finally:
            self.close()


