def run_publisher():
    """Run the publisher to send sample tasks."""
    publisher = TaskPublisher()

    try:
        publisher.connect()

        # Publish individual tasks
        publisher.publish_task(
            task_type="send_email",
            payload={
                "recipient": "user@example.com",
                "subject": "Welcome!",
                "body": "Welcome to our platform.",
            },
        )

        publisher.publish_task(
            task_type="process_data",
            payload={
                "dataset": "user_analytics",
                "operation": "aggregate",
                "filters": {"date": "2024-01-01"},
            },
            priority=5,
        )

        publisher.publish_task(
            task_type="generate_report",
            payload={
                "report_type": "monthly_sales",
                "date_range": "2024-01",
                "format": "pdf",
            },
        )

        # Publish a batch of notification tasks
        notification_tasks = [
            {
                "task_type": "send_notification",
                "payload": {
                    "user_id": f"user_{i}",
                    "message": f"You have {i} new updates!",
                },
                "priority": 1,
            }
            for i in range(1, 6)
        ]

        publisher.publish_batch(notification_tasks)

        # Publish an unknown task type to test default handler
        publisher.publish_task(
            task_type="unknown_task",
            payload={"data": "some data for unknown task type"},
        )

        print("\n[*] All tasks published successfully!")

    except pika.exceptions.AMQPConnectionError as e:
        print(f"[!] Connection error: {e}")
        print("[!] Make sure RabbitMQ is running at localhost:5672")
    except Exception as e:
        print(f"[!] Error: {e}")
    finally:
        publisher.close()


def run_consumer():
    """Run the consumer to process tasks."""
    consumer = TaskConsumer(prefetch_count=1)

    try:
        consumer.connect()

        # Register task handlers
        consumer.register_handler("send_email", handle_email_task)
        consumer.register_handler("process_data", handle_data_processing_task)
        consumer.register_handler("generate_report", handle_report_generation_task)
        consumer.register_handler("send_notification", handle_notification_task)
        consumer.set_default_handler(default_handler)

        # Start consuming (blocks until interrupted)
        consumer.start_consuming()

    except pika.exceptions.AMQPConnectionError as e:
        print(f"[!] Connection error: {e}")
        print("[!] Make sure RabbitMQ is running at localhost:5672")
    except Exception as e:
        print(f"[!] Error: {e}")
    finally:
        consumer.close()


def print_usage():
    """Print usage instructions."""
    print("Distributed Task Processing System")
    print("=" * 50)
    print("\nUsage:")
    print(f"  python {sys.argv[0]} publisher  - Send sample tasks")
    print(f"  python {sys.argv[0]} consumer   - Start processing tasks")
    print(f"  python {sys.argv[0]} both       - Send tasks then consume them")
    print("\nPrerequisites:")
    print("  - RabbitMQ server running at localhost:5672")
    print("  - pip install pika")


if __name__ == "__main__":
    if len(sys.argv) < 2:
        print_usage()
        sys.exit(1)

    mode = sys.argv[1].lower()

    if mode == "publisher":
        run_publisher()
    elif mode == "consumer":
        run_consumer()
    elif mode == "both":
        print("=" * 50)
        print("Publishing tasks...")
        print("=" * 50)
        run_publisher()
        print("\n" + "=" * 50)
        print("Starting consumer...")
        print("=" * 50)
        run_consumer()
    else:
        print(f"Unknown mode: {mode}")
        print_usage()
        sys.exit(1)